const express = require('express');
const twilio = require('twilio');
const session = require('express-session');
const crypto = require('crypto');
const rateLimit = require('express-rate-limit');

const app = express();
app.use(express.json());
app.use(session({
  secret: process.env.SESSION_SECRET || 'fallback-secret-key',
  resave: false,
  saveUninitialized: false,
  cookie: { secure: process.env.NODE_ENV === 'production' }
}));

// Rate limiting for SMS requests
const smsLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // limit each IP to 5 requests per windowMs
  message: 'Too many SMS requests, please try again later'
});

// Rate limiting for code verification
const verifyLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 10,
  message: 'Too many verification attempts, please try again later'
});

// Twilio configuration
const client = twilio(
  process.env.TWILIO_ACCOUNT_SID,
  process.env.TWILIO_AUTH_TOKEN
);

// In-memory storage for codes (use Redis in production)
const codeStorage = new Map();

// Generate 6-digit code
function generateCode() {
  return Math.floor(100000 + Math.random() * 900000).toString();
}

// Send SMS with rate limiting
app.post('/send-sms', smsLimiter, async (req, res) => {
  try {
    const { phoneNumber } = req.body;
    
    if (!phoneNumber) {
      return res.status(400).json({ error: 'Phone number is required' });
    }
    
    // Generate and store code with expiration
    const code = generateCode();
    const expiration = Date.now() + 5 * 60 * 1000; // 5 minutes
    
    // Store code with user session
    const sessionId = req.sessionID;
    codeStorage.set(sessionId, {
      code,
      phoneNumber,
      expiresAt: expiration
    });
    
    // Send SMS
    await client.messages.create({
      body: `Your verification code is: ${code}`,
      from: process.env.TWILIO_PHONE_NUMBER,
      to: phoneNumber
    });
    
    res.json({ message: 'Verification code sent' });
  } catch (error) {
    console.error('SMS sending error:', error);
    res.status(500).json({ error: 'Failed to send SMS' });
  }
});

// Verify code with rate limiting
app.post('/verify-code', verifyLimiter, async (req, res) => {
  try {
    const { code } = req.body;
    const sessionId = req.sessionID;
    
    if (!code) {
      return res.status(400).json({ error: 'Code is required' });
    }
    
    const storedData = codeStorage.get(sessionId);
    
    if (!storedData) {
      return res.status(400).json({ error: 'No active verification session' });
    }
    
    // Check expiration
    if (Date.now() > storedData.expiresAt) {
      codeStorage.delete(sessionId);
      return res.status(400).json({ error: 'Verification code expired' });
    }
    
    // Secure comparison to prevent timing attacks
    const isMatch = crypto.timingSafeEqual(
      Buffer.from(code),
      Buffer.from(storedData.code)
    );
    
    if (isMatch) {
      // Clear the code after successful verification
      codeStorage.delete(sessionId);
      req.session.verified = true;
      res.json({ message: 'Verification successful' });
    } else {
      res.status(400).json({ error: 'Invalid verification code' });
    }
  } catch (error) {
    console.error('Verification error:', error);
    res.status(500).json({ error: 'Verification failed' });
  }
});

// Clear session on logout
app.post('/logout', (req, res) => {
  const sessionId = req.sessionID;
  codeStorage.delete(sessionId);
  req.session.destroy();
  res.json({ message: 'Logged out successfully' });
});

module.exports = app;